import base64
import base64
import os


image_directory = 'images/text'
output_img_dir = 'images/out'

encoded_string = ''

images = os.listdir(image_directory)

for image in images:
    with open(f"{image_directory}/{image}", "rb") as fd1:
        encoded_string = fd1.read()

        decoded_image_bytes = base64.b64decode(encoded_string)


    with open(f"{output_img_dir}/{image[:-4]}.png", "wb") as fd2:
        fd2.write(decoded_image_bytes)

